import{f as r,o as a,c as i,a2 as o}from"./chunks/framework.DHYrF-q6.js";const h=JSON.parse('{"title":"Spring 生态","description":"","frontmatter":{},"headers":[],"relativePath":"spring-ecosystem/index.md","filePath":"spring-ecosystem/index.md","lastUpdated":1780734044000}'),e={name:"spring-ecosystem/index.md"};function n(l,t,d,s,c,p){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="spring-生态" tabindex="-1">Spring 生态 <a class="header-anchor" href="#spring-生态" aria-label="Permalink to &quot;Spring 生态&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>Spring 生态是 Java 后端开发的绝对核心，涵盖 Spring Framework 基础、Spring Boot 自动配置、Spring Cloud 微服务、Spring Security 安全框架以及 Spring Data 持久层抽象。掌握 Spring 生态不仅是为了应对面试，更是日常开发的生产力基础。</p><div class="tip custom-block"><p class="custom-block-title">核心思路</p><p>不要停留在会用注解，要理解<strong>自动配置原理</strong>、<strong>Bean 生命周期</strong>、<strong>AOP 实现机制</strong>和<strong>扩展点设计</strong>。</p></div><div class="info custom-block"><p class="custom-block-title">技术栈</p><p>Spring Framework 6.x / Spring Boot 3.x / Spring Cloud 2023+ / Spring Security 6.x</p></div><h2 id="核心知识点" tabindex="-1">核心知识点 <a class="header-anchor" href="#核心知识点" aria-label="Permalink to &quot;核心知识点&quot;">​</a></h2><h3 id="spring-framework-核心" tabindex="-1">Spring Framework 核心 <a class="header-anchor" href="#spring-framework-核心" aria-label="Permalink to &quot;Spring Framework 核心&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>IoC 容器</td><td>BeanFactory vs ApplicationContext、BeanDefinition、BeanPostProcessor 扩展点</td></tr><tr><td>Bean 生命周期</td><td>实例化 → 属性填充 → 初始化 → 使用 → 销毁，各阶段回调接口</td></tr><tr><td>依赖注入</td><td>@Autowired / @Resource 区别、构造器注入 vs 字段注入、循环依赖三级缓存</td></tr><tr><td>AOP</td><td>JDK 动态代理 vs CGLIB、切面表达式、Advice 类型、AOP 失效场景</td></tr><tr><td>事务管理</td><td>声明式事务原理、传播行为 7 种、隔离级别、事务失效的 8 种场景</td></tr><tr><td>事件机制</td><td>ApplicationEvent / ApplicationListener、异步事件处理</td></tr></tbody></table><h3 id="spring-boot" tabindex="-1">Spring Boot <a class="header-anchor" href="#spring-boot" aria-label="Permalink to &quot;Spring Boot&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>自动配置</td><td>@EnableAutoConfiguration 原理、spring.factories / AutoConfiguration.imports、条件注解</td></tr><tr><td>起步依赖</td><td>starter 命名规范、自定义 starter 开发</td></tr><tr><td>监控</td><td>Actuator 端点、Micrometer + Prometheus 集成、自定义 HealthIndicator</td></tr><tr><td>配置加载</td><td>配置优先级、多环境配置、@ConfigurationProperties</td></tr><tr><td>嵌入式容器</td><td>Tomcat/Jetty/Undertow 参数调优</td></tr></tbody></table><h3 id="spring-cloud-微服务" tabindex="-1">Spring Cloud 微服务 <a class="header-anchor" href="#spring-cloud-微服务" aria-label="Permalink to &quot;Spring Cloud 微服务&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>服务注册与发现</td><td>Nacos / Eureka / Consul 对比、CAP 权衡、健康检查机制</td></tr><tr><td>配置中心</td><td>Nacos Config 动态刷新原理、配置灰度发布</td></tr><tr><td>远程调用</td><td>OpenFeign 原理、负载均衡策略、超时与重试机制</td></tr><tr><td>服务网关</td><td>Spring Cloud Gateway 路由谓词、过滤器链、限流实现</td></tr><tr><td>熔断降级</td><td>Sentinel 资源定义、流控/熔断/热点规则、控制台使用</td></tr><tr><td>分布式事务</td><td>Seata AT/TCC/Saga 模式对比、TC/TM/RM 三组件架构</td></tr></tbody></table><h3 id="spring-security" tabindex="-1">Spring Security <a class="header-anchor" href="#spring-security" aria-label="Permalink to &quot;Spring Security&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>认证流程</td><td>SecurityContextHolder → AuthenticationManager → ProviderManager 链路</td></tr><tr><td>授权模型</td><td>RBAC 权限模型、方法级安全注解、表达式控制</td></tr><tr><td>OAuth2/JWT</td><td>授权码模式、密码模式、JWT 结构（Header/Payload/Signature）、Token 刷新</td></tr><tr><td>常见漏洞</td><td>CSRF / CORS / XSS / SQL 注入防护配置</td></tr></tbody></table><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>Spring Bean 生命周期</strong>：完整描述从扫描到销毁的全链路，PostProcessor 的执行顺序</li><li><strong>循环依赖</strong>：Spring 如何用三级缓存解决？为什么需要三级缓存而不是两级？</li><li><strong>@Transactional 失效场景</strong>：非 public 方法、自调用、异常被捕获、rollbackFor 未指定等</li><li><strong>Spring Boot 自动配置原理</strong>：从 @SpringBootApplication 入口到条件装配的完整链路</li><li><strong>MyBatis 与 Spring 整合</strong>：MapperScannerConfigurer、SqlSessionFactory、Mapper 代理工厂</li><li><strong>微服务组件对比</strong>：Nacos vs Eureka、Sentinel vs Hystrix、Gateway vs Zuul</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>只知道用注解，不知道 Bean 是如何被管理和增强的</li><li>循环依赖只背答案，不理解三级缓存中每一级的作用</li><li>事务失效场景说不全，或者不会举实际例子</li><li>Spring Cloud 组件停留在会用，不关注实现原理</li></ul></div><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="阶段一-spring-framework-基础-2-周" tabindex="-1">阶段一：Spring Framework 基础（2 周） <a class="header-anchor" href="#阶段一-spring-framework-基础-2-周" aria-label="Permalink to &quot;阶段一：Spring Framework 基础（2 周）&quot;">​</a></h3><ol><li>从 ApplicationContext 入口打断点，Debug 走一遍 Bean 加载全流程</li><li>手写一个简易 IoC 容器，实现 @Autowired 注入和 @PostConstruct 初始化</li><li>画出 Bean 生命周期时序图，标注每个后置处理器的执行节点</li></ol><h3 id="阶段二-spring-boot-实战-2-周" tabindex="-1">阶段二：Spring Boot 实战（2 周） <a class="header-anchor" href="#阶段二-spring-boot-实战-2-周" aria-label="Permalink to &quot;阶段二：Spring Boot 实战（2 周）&quot;">​</a></h3><ol start="4"><li>实现一个自定义 starter，深入理解自动配置机制</li><li>搭建完整的 Actuator + Prometheus + Grafana 监控体系</li><li>分析 spring-boot-autoconfigure 源码中的关键配置类</li></ol><h3 id="阶段三-微服务体系-3-周" tabindex="-1">阶段三：微服务体系（3 周） <a class="header-anchor" href="#阶段三-微服务体系-3-周" aria-label="Permalink to &quot;阶段三：微服务体系（3 周）&quot;">​</a></h3><ol start="7"><li>搭建一个完整的 Spring Cloud 微服务项目（Gateway + Nacos + Feign + Sentinel + Seata）</li><li>进行压测，验证 Sentinel 限流和熔断效果</li><li>阅读 OpenFeign 动态代理生成与 HTTP 请求发送的核心代码</li></ol><h3 id="阶段四-源码串联-1-周" tabindex="-1">阶段四：源码串联（1 周） <a class="header-anchor" href="#阶段四-源码串联-1-周" aria-label="Permalink to &quot;阶段四：源码串联（1 周）&quot;">​</a></h3><ol start="10"><li>以 MyBatis 整合为例，串联 MyBatis AutoConfiguration → SqlSessionFactory → MapperProxy 全链路</li></ol><details class="details custom-block"><summary>推荐书单</summary><ul><li>《Spring 实战（第6版）》—— Craig Walls</li><li>《Spring 源码深度解析（第2版）》—— 郝佳</li><li>《Spring Boot 编程思想（核心篇）》—— 小马哥</li><li>《Spring Cloud 微服务实战》—— 翟永超</li><li>《Spring Security 实战》—— Laurentiu Spilca</li></ul></details>',27)])])}const u=r(e,[["render",n]]);export{h as __pageData,u as default};
